// src/utils/mixing.ts
import type { RGB, PaintProfile } from '../config';
import { srgbToLinear, linearToSrgb, rgbToHsl, hslToRgb } from './colorMath';

export function reflectanceToKS(R: number): number {
  const r = Math.max(0.001, Math.min(0.999, R));
  return ((1 - r) * (1 - r)) / (2 * r);
}

export function ksToReflectance(ks: number): number {
  return 1 + ks - Math.sqrt(ks * ks + 2 * ks);
}

export function mixLinearRgb(drops: number[], componentsRgb: RGB[]): RGB {
  let total = 0;
  for (let i = 0; i < drops.length; i++) total += drops[i];
  if (total === 0) return [0, 0, 0];

  let lr = 0, lg = 0, lb = 0;
  for (let i = 0; i < drops.length; i++) {
    if (drops[i] <= 0) continue;
    const w = drops[i] / total;
    lr += w * srgbToLinear(componentsRgb[i][0]);
    lg += w * srgbToLinear(componentsRgb[i][1]);
    lb += w * srgbToLinear(componentsRgb[i][2]);
  }

  return [
    Math.round(linearToSrgb(lr) * 255),
    Math.round(linearToSrgb(lg) * 255),
    Math.round(linearToSrgb(lb) * 255),
  ];
}

// ---------------------------------------------------------
// PIGMENT COLOR WHEEL (RYB) MAPPING
// Искривляем цифровой круг RGB в круг художников RYB
// ---------------------------------------------------------
function hueRgbToRyb(h: number): number {
  if (h < 60) return h * 2;                       // Красный -> Желтый
  if (h < 120) return 120 + (h - 60);             // Желтый -> Зеленый
  if (h < 240) return 180 + (h - 120) * 0.5;      // Зеленый -> Синий
  return 240 + (h - 240);                         // Синий -> Красный
}

function hueRybToRgb(h: number): number {
  if (h < 120) return h * 0.5;
  if (h < 180) return 60 + (h - 120);
  if (h < 240) return 120 + (h - 180) * 2;
  return 240 + (h - 240);
}

// ---------------------------------------------------------
// ГЛАВНАЯ ФУНКЦИЯ СМЕШИВАНИЯ КРАСОК (HYBRID RYB)
// ---------------------------------------------------------
export function mixKubelkaMunk(drops: number[], componentsRgb: RGB[]): RGB {
  let total = 0;
  for (let i = 0; i < drops.length; i++) total += drops[i];
  if (total === 0) return [0, 0, 0];

  let vecX = 0, vecY = 0;
  let sumL = 0;
  let sumSatWeight = 0;

  for (let i = 0; i < drops.length; i++) {
    if (drops[i] <= 0) continue;
    const w = drops[i] / total;
    const [r, g, b] = componentsRgb[i];
    
    // Переводим в HSL (h: 0-360, s: 0-1, l: 0-1)
    const [h, s, l] = rgbToHsl([r, g, b]);

    // 1. СМЕШИВАНИЕ ОТТЕНКА (RYB Векторы)
    const rybH = hueRgbToRyb(h);
    const rad = rybH * Math.PI / 180;
    
    // Вес вектора зависит от насыщенности, чтобы серые цвета не ломали оттенок
    const weight = w * (s + 0.1); 
    vecX += Math.cos(rad) * weight;
    vecY += Math.sin(rad) * weight;
    sumSatWeight += weight;

    // 2. СМЕШИВАНИЕ ЯРКОСТИ (Субтрактивное / Физическое поглощение)
    // Используем логарифм для имитации поглощения света
    sumL += w * Math.log(Math.max(0.001, l));
  }

  // Восстанавливаем Оттенок (Hue)
  let finalH_ryb = (Math.atan2(vecY, vecX) * 180) / Math.PI;
  if (finalH_ryb < 0) finalH_ryb += 360;
  const finalH = hueRybToRgb(finalH_ryb);

  // Восстанавливаем Насыщенность (Saturation)
  const R = Math.sqrt(vecX * vecX + vecY * vecY);
  const ratio = sumSatWeight > 0 ? (R / sumSatWeight) : 0;
  // Насыщенность падает, если смешивать противоположные цвета (ratio стремится к 0)
  const finalS = Math.min(1, sumSatWeight * ratio * 1.5); 

  // Восстанавливаем Яркость (Lightness)
  let finalL = Math.exp(sumL);

  // Дополнительное затемнение при смешивании противоположных цветов (образование коричневого/грязи)
  finalL = finalL * (0.6 + 0.4 * ratio);

  return hslToRgb(finalH, finalS, finalL);
}

export function mixColors(
  drops: number[],
  componentsRgb: RGB[],
  profile: PaintProfile,
  substrateColor: RGB = [255, 255, 255],
): RGB {
  const total = drops.reduce((s, d) => s + d, 0);
  if (total === 0) return [0, 0, 0];

  if (profile.id === 'digital') {
    return mixLinearRgb(drops, componentsRgb);
  }

  // Получаем базовый реалистичный цвет
  const baseMix = mixKubelkaMunk(drops, componentsRgb);
  let result = baseMix;

  if (profile.usesSubstrate) {
     // Возвращаем более тонкий лимит прозрачности, чтобы сохранить реалистичность акварели
     const maxT = Math.min(0.25, profile.transparency * 0.3); 
     const effAlpha = 1 - maxT;

     result = [
       Math.round(baseMix[0] * effAlpha + substrateColor[0] * maxT),
       Math.round(baseMix[1] * effAlpha + substrateColor[1] * maxT),
       Math.round(baseMix[2] * effAlpha + substrateColor[2] * maxT),
     ];
  }

  const numColors = drops.filter(d => d > 0).length;
  // Возвращаем линейное затемнение, так как RYB эвристика уже не так сильно затемняет цвета, 
  // как моя предыдущая сломанная RGB K/S версия
  const darkening = 1 - profile.darkeningFactor * Math.max(0, numColors - 2) * 0.25;

  return [
    Math.max(0, Math.min(255, Math.round(result[0] * darkening))),
    Math.max(0, Math.min(255, Math.round(result[1] * darkening))),
    Math.max(0, Math.min(255, Math.round(result[2] * darkening))),
  ];
}

// Заглушка, чтобы не ломать импорты в других файлах
export function mixWithSubstrate(
  drops: number[], componentsRgb: RGB[], substrateColor: RGB, transparency: number, kmWeight: number
): RGB {
  return mixColors(drops, componentsRgb, { id: 'watercolor', usesSubstrate: true, transparency, darkeningFactor: 0 } as any, substrateColor);
}