// src/engine/worker.ts
import type { RGB, PaintProfile } from '../config';
import { rgbToLab, deltaE00 } from '../utils/colorMath';
import { mixColors } from '../utils/mixing';
import { createPRNG, hashRGB } from '../utils/prng';
import type { SolverCandidate } from './types';

export interface WorkerEventData {
  target: RGB;
  crgb: RGB[];
  n: number;
  mpc: number;
  isF: boolean;
  tt: number | null;
  tLab: [number, number, number];
  profile: PaintProfile;
  subColor: RGB;
  maxMix: number;
  jobId: number; // Добавлен идентификатор задачи
}

let deltaMemo = new Map<string, number>();

function computeDelta(
  drops: number[],
  componentsRgb: RGB[],
  targetLab: [number, number, number],
  profile: PaintProfile,
  substrateColor: RGB
): number {
  if (drops.reduce((s, d) => s + d, 0) === 0) return Infinity;
  
  const key = drops.join(',');
  if (deltaMemo.has(key)) return deltaMemo.get(key)!;
  
  const mixed = mixColors(drops, componentsRgb, profile, substrateColor);
  const d = deltaE00(targetLab, rgbToLab(mixed));
  
  deltaMemo.set(key, d);
  return d;
}

function greedyProportions(
  targetLab: [number, number, number],
  componentsRgb: RGB[],
  totalUnits: number,
  profile: PaintProfile,
  substrateColor: RGB,
  maxColorsInMix: number
): number[] {
  const n = componentsRgb.length;
  const drops = new Array(n).fill(0);

  for (let step = 0; step < totalUnits; step++) {
    let bestIdx = 0, bestD = Infinity;
    const usedColors = new Set<number>();
    for (let i = 0; i < n; i++) if (drops[i] > 0) usedColors.add(i);

    for (let i = 0; i < n; i++) {
      if (!usedColors.has(i) && usedColors.size >= maxColorsInMix) continue;
      const td = [...drops];
      td[i]++;
      const d = computeDelta(td, componentsRgb, targetLab, profile, substrateColor);
      if (d < bestD) { bestD = d; bestIdx = i; }
    }
    drops[bestIdx]++;
  }
  return drops;
}

function hillClimb(
  targetLab: [number, number, number],
  componentsRgb: RGB[],
  init: number[],
  maxPC: number,
  isFixed: boolean,
  targetTotal: number | null,
  maxRounds: number,
  profile: PaintProfile,
  substrateColor: RGB,
  maxColorsInMix: number,
  dropPen = 0.002,
  colorPen = 0
): number[] {
  const n = componentsRgb.length;
  let drops = [...init];
  let bestD = computeDelta(drops, componentsRgb, targetLab, profile, substrateColor);

  const score = (d: number[], delta: number) => {
    if (isFixed) return delta;
    const usedColors = d.filter(v => v > 0).length;
    const overLimit = Math.max(0, usedColors - maxColorsInMix);
    
    const totalDrops = d.reduce((s, v) => s + v, 0);
    const dropsPenalty = totalDrops <= 10 
      ? (totalDrops * 0.05) 
      : (10 * 0.05 + Math.pow(totalDrops - 10, 1.5) * 0.1);
      
    return delta + dropsPenalty + colorPen * usedColors + overLimit * 50;
  };

  let bestS = score(drops, bestD);

  for (let round = 0; round < maxRounds; round++) {
    let improved = false;
    for (let i = 0; i < n; i++) {
      for (const step of [-1, 1, -2, 2]) {
        const nd = [...drops];
        nd[i] = Math.max(0, Math.min(maxPC, nd[i] + step));
        if (nd[i] === drops[i]) continue;

        const usedAfter = nd.filter(v => v > 0).length;
        if (usedAfter > maxColorsInMix && nd[i] > 0 && drops[i] === 0) continue;

        if (isFixed && targetTotal !== null) {
          const diff = nd.reduce((s, d) => s + d, 0) - targetTotal;
          if (diff !== 0) {
            let ok = false;
            for (let j = 0; j < n; j++) {
              if (j === i) continue;
              const c = nd[j] - diff;
              if (c >= 0 && c <= maxPC) { nd[j] = c; ok = true; break; }
            }
            if (!ok) continue;
          }
        }

        const d = computeDelta(nd, componentsRgb, targetLab, profile, substrateColor);
        const s = score(nd, d);

        if (s < bestS - 0.0001) {
          drops = nd; bestD = d; bestS = s; improved = true;
        }
      }
    }
    if (!improved) break;
  }
  return drops;
}

self.onmessage = function (e: MessageEvent<WorkerEventData>) {
  deltaMemo.clear();
  const { target, crgb, n, mpc, isF, tt, tLab, profile, subColor, maxMix, jobId } = e.data;
  
  const cands: SolverCandidate[] = [];
  const random = createPRNG(hashRGB(target));
  
  const ac = (drops: number[]) => {
    const t = drops.reduce((s, d) => s + d, 0);
    if (t === 0) return;
    const d = computeDelta(drops, crgb, tLab, profile, subColor);
    cands.push({ drops: [...drops], delta: d, total: t, used: drops.filter(v => v > 0).length });
  };

  const dist = crgb.map((c, i) => ({
    i,
    d: Math.sqrt((target[0] - c[0]) ** 2 + (target[1] - c[1]) ** 2 + (target[2] - c[2]) ** 2)
  }));
  dist.sort((a, b) => a.d - b.d);
  
  const topK = Math.min(12, n);
  const topI = dist.slice(0, topK).map(x => x.i);

  const scales = isF && tt ? [tt] : [2, 3, 4, 5, 6, 8, 10, 13, 17, 22, 30];

  for (const s of scales) {
    const d = greedyProportions(tLab, crgb, Math.min(s, mpc * n), profile, subColor, maxMix);
    for (let i = 0; i < n; i++) d[i] = Math.min(d[i], mpc);
    for (const [dp, cp] of [[.05, .3], [.02, .1], [.005, 0], [0, 0]]) {
      ac(hillClimb(tLab, crgb, d, mpc, isF, tt, 80, profile, subColor, maxMix, dp, cp));
    }
  }

  self.postMessage({ type: 'progress', value: 20, jobId });

  for (let i = 0; i < n; i++) {
    const d = new Array(n).fill(0);
    d[i] = isF && tt ? tt : 1;
    if (d[i] <= mpc) ac(d);
  }

  self.postMessage({ type: 'progress', value: 25, jobId });

  for (let a = 0; a < topI.length; a++) {
    for (let b = a + 1; b < topI.length; b++) {
      if (2 > maxMix) continue;
      const ii = topI[a], jj = topI[b];
      const pr: RGB[] = [crgb[ii], crgb[jj]];
      const pProfile = { ...profile, darkeningFactor: 0 };
      
      for (const tot of (isF && tt ? [tt] : [2, 4, 8, 15])) {
        const pd = greedyProportions(tLab, pr, tot, pProfile, subColor, 2);
        const fd = new Array(n).fill(0);
        fd[ii] = Math.min(pd[0], mpc);
        fd[jj] = Math.min(pd[1], mpc);
        
        for (const [dp, cp] of [[.05, .5], [.01, 0]]) {
          ac(hillClimb(tLab, crgb, fd, mpc, isF, tt, 50, profile, subColor, maxMix, dp, cp));
        }
      }
    }
  }

  self.postMessage({ type: 'progress', value: 45, jobId });

  const tpT = Math.min(8, n);
  const tI = dist.slice(0, tpT).map(x => x.i);

  for (let a = 0; a < tI.length; a++) {
    for (let b = a + 1; b < tI.length; b++) {
      for (let c = b + 1; c < tI.length; c++) {
        if (3 > maxMix) continue;
        const ii = tI[a], jj = tI[b], kk = tI[c];
        const tr: RGB[] = [crgb[ii], crgb[jj], crgb[kk]];
        const tProfile = { ...profile, darkeningFactor: 0 };

        for (const tot of (isF && tt ? [tt] : [3, 8, 15])) {
          const td = greedyProportions(tLab, tr, tot, tProfile, subColor, 3);
          const fd = new Array(n).fill(0);
          fd[ii] = Math.min(td[0], mpc);
          fd[jj] = Math.min(td[1], mpc);
          fd[kk] = Math.min(td[2], mpc);
          
          ac(hillClimb(tLab, crgb, fd, mpc, isF, tt, 50, profile, subColor, maxMix, .03, .2));
          ac(hillClimb(tLab, crgb, fd, mpc, isF, tt, 50, profile, subColor, maxMix, 0, 0));
        }
      }
    }
  }

  self.postMessage({ type: 'progress', value: 65, jobId });

  const totalR = Math.min(1200, n * 50);

  for (let iter = 0; iter < totalR; iter++) {
    const d = new Array(n).fill(0);
    const cnt = 2 + Math.floor(random() * Math.min(3, maxMix - 1));
    const idx: number[] = [];
    const avail = Array.from({ length: n }, (_, i) => i);
    
    for (let j = 0; j < Math.min(cnt, n, maxMix); j++) {
      const p = Math.floor(random() * avail.length);
      idx.push(avail[p]); 
      avail.splice(p, 1);
    }
    
    if (isF && tt) {
      let rem = tt, valid = true;
      for (let j = 0; j < idx.length - 1; j++) {
        const mx = Math.min(mpc, rem - (idx.length - j - 1));
        if (mx < 1) { valid = false; break; }
        d[idx[j]] = 1 + Math.floor(random() * mx);
        rem -= d[idx[j]];
      }
      if (!valid || rem < 1 || rem > mpc) continue;
      d[idx[idx.length - 1]] = rem;
    } else {
      for (const i of idx) d[i] = 1 + Math.floor(random() * Math.min(mpc, 12));
    }
    
    const dp = random() < .5 ? .03 : 0, cp = random() < .3 ? .2 : 0;
    ac(hillClimb(tLab, crgb, d, mpc, isF, tt, 25, profile, subColor, maxMix, dp, cp));
    
    if (iter % 150 === 0) {
        self.postMessage({ type: 'progress', value: 65 + Math.round((iter / totalR) * 30), jobId });
    }
  }

  self.postMessage({ type: 'progress', value: 96, jobId });

  cands.sort((a, b) => a.delta - b.delta);
  for (const c of cands.slice(0, 20)) {
    ac(hillClimb(tLab, crgb, c.drops, mpc, isF, tt, 300, profile, subColor, maxMix, 0, 0));
    ac(hillClimb(tLab, crgb, c.drops, mpc, isF, tt, 300, profile, subColor, maxMix, .05, .3));
  }

  self.postMessage({ type: 'progress', value: 100, jobId });
  self.postMessage({ type: 'result', candidates: cands, jobId });
};